const id = $input.first().json.body?.id || $input.first().json.id;
const binaryKey = Object.keys($input.first().binary || {})[0] || 'data';

if (!id) throw new Error('Campo id não encontrado no body da requisição.');
if (!$input.first().binary?.[binaryKey]) throw new Error('Arquivo PDF não encontrado.');

return [{
  json: { id, binaryKey },
  binary: $input.first().binary
}];

const resumeId = $('Code - Valida id e binário').first().json.id;
const content = $input.first().json.message?.content || $input.first().json.choices?.[0]?.message?.content;

let parsed;
try {
  parsed = typeof content === 'string' ? JSON.parse(content) : content;
} catch(e) {
  throw new Error('GPT-4o não retornou JSON válido: ' + content);
}

return [{
  json: {
    resume_id: resumeId,
    employability_score: parsed.employability_score,
    ats_rejection_chance: parsed.ats_rejection_chance,
    hook_message: parsed.hook_message,
    brutal_roast: parsed.brutal_roast,
    red_flags: JSON.stringify(parsed.red_flags),
    improvement_tips: JSON.stringify(parsed.improvement_tips),
    rewritten_summary: parsed.rewritten_summary,
    status: 'analyzed',
    created_at: new Date().toISOString()
  }
}];

